SELECT option_id , question_id , option_text , option_value , sort_order , score , reg_dt FROM tbl_survey_option WHERE question_id IN
#{id}
ORDER BY question_id, sort_order

SELECT A.OPTION_ID , A.QUESTION_ID , A.OPTION_TEXT , A.OPTION_VALUE , A.SORT_ORDER , A.SCORE , A.REG_DT , COUNT(B.SELECTED_VALUE) AS SELECTED_COUNT FROM TBL_SURVEY_OPTION A LEFT JOIN TBL_SURVEY_ANSWER B ON A.QUESTION_ID = B.QUESTION_ID AND B.SELECTED_VALUE = A.OPTION_VALUE WHERE A.QUESTION_ID IN
#{id}
GROUP BY A.OPTION_ID, A.QUESTION_ID, A.OPTION_TEXT, A.OPTION_VALUE, A.SORT_ORDER, A.SCORE, A.REG_DT ORDER BY A.QUESTION_ID, A.SORT_ORDER

